class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        int s1Len = s1.length(), s2Len = s2.length();
        int[] s1Count = new int[s2Len];
        int[] s1Index = new int[s2Len];

        int s2Index = 0, count = 0;
        for (int i = 0; i < s1Len; ++i) {
            if (s1.charAt(i) == s2.charAt(s2Index)) {
                ++s2Index;
                if (s2Index == s2Len) {
                    ++count;
                    s2Index = 0;
                }
            }
            if (s2Index < s2Len) {
                s1Count[s2Index]++;
                s1Index[s2Index] = i;
            }
        }

        if (count == 0) return 0;

        int res = n1 * count / n2;
        for (int i = 0; i < s2Len; ++i) {
            if (s1Index[i] == s1Len - 1) continue;
            int nextCount = count + 
                (n1 - 1 - s1Index[i]) / s1Len * count + 
                getCount(s1, s1Index[i] + 1, s2, i);
            res = Math.max(res, (nextCount / n2));
        }
        return res;
    }

    private int getCount(String s1, int start, String s2, int s2Index) {
        int count = 0;
        for (int i = start; i < s1.length(); ++i) {
            if (s1.charAt(i) == s2.charAt(s2Index)) {
                ++s2Index;
                if (s2Index == s2.length()) {
                    ++count;
                    s2Index = 0;
                }
            }
        }
        return count;
    }
}
